mapper.select:
SELECT COUNT(1) FROM exam_answer
WHERE (mark_exams IS NULL OR mark_exams='')
  AND exam_id=#{examId};

SELECT COUNT(1) FROM exam_answer
WHERE right_sign = '验签成功'
  AND exam_id=#{examId};

SELECT COUNT(1) FROM exam_answer
WHERE (right_sign != '验签成功' OR right_sign IS NULL)
  AND exam_id=#{examId};

SELECT COUNT(1)
FROM exam_answer ea
         INNER JOIN exam_paper ep ON ea.paper_id = ep.id
WHERE ep.question_type = #{questionType}
  AND ea.exam_id = #{examId}
  AND ea.mark_exams IS NOT NULL AND ea.mark_exams!='';

SELECT COUNT(1)
FROM exam_answer ea
         INNER JOIN exam_paper ep ON ea.paper_id = ep.id
WHERE ep.question_type = #{questionType}
  AND ea.exam_id = #{examId}
  AND (ea.mark_exams IS NULL OR ea.mark_exams='');

SELECT COUNT(1)
FROM exam_answer ea
         INNER JOIN exam_paper ep ON ea.paper_id = ep.id
WHERE ep.question_type = #{questionType}
  AND ea.exam_id = #{examId}
  AND ea.right_sign = '验签成功';

SELECT COUNT(1)
FROM exam_answer ea
         INNER JOIN exam_paper ep ON ea.paper_id = ep.id
WHERE ep.question_type = #{questionType}
  AND ea.exam_id = #{examId}
  AND (ea.right_sign != '验签成功' OR ea.right_sign IS NULL);

SELECT COUNT(1) FROM exam_answer
WHERE exam_id=#{examId}
  AND student_id=#{studentId};

SELECT COUNT(1)
FROM exam_answer ea
         INNER JOIN exam_paper ep ON ea.paper_id = ep.id
WHERE ep.question_type = #{questionType}
AND ea.exam_id = #{examId}
  AND student_id=#{studentId};

SELECT COUNT(1) FROM exam_paper
WHERE exam_id=#{examId}
AND question_type=#{questionType};

SELECT COUNT(1) FROM course_student
WHERE course_id=#{courseId}
AND is_add=#{isAdd};
